### Step-by-Step Example

#### 1. Set Up the Project
First, we need to set up a basic Node.js project with Express and SQLite.

1. **Initialize the Project**:
   ```sh
   mkdir form-data-storage
   cd form-data-storage
   npm init -y
   ```

2. **Install Dependencies**:
   ```sh
   npm install express sqlite3 body-parser
   ```

3. **Create the Server**:
   Create a file named `server.js` and add the following code:

```javascript
const express = require('express');
const bodyParser = require('body-parser');
const sqlite3 = require('sqlite3').verbose();

const app = express();
app.use(bodyParser.json());
app.use(bodyParser.urlencoded({ extended: true }));

// Connect to SQLite database
const db = new sqlite3.Database(':memory:', (err) => {
    if (err) {
        console.error(err.message);
    } else {
        console.log('Connected to the in-memory SQlite database.');
    }
});

// Create a table
db.serialize(() => {
    db.run("CREATE TABLE IF NOT EXISTS users (id INTEGER PRIMARY KEY AUTOINCREMENT, username TEXT, email TEXT)");
});

// Route to handle form submissions
app.post('/submit-form', (req, res) => {
    const { username, email } = req.body;

    if (!username || !email) {
        return res.status(400).send('Username and email are required.');
    }

    // Insert the data into the database
    db.run("INSERT INTO users (username, email) VALUES (?, ?)", [username, email], function(err) {
        if (err) {
            return res.status(500).send('Error inserting data into the database.');
        }
        res.send(`User ${username} with email ${email} has been saved.`);
    });
});

// Start the server
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
    console.log(`Server is running on port ${PORT}`);
});
```

